#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Calculate numerator: 2i+1
        int numerator = 2 * i + 1;

        // Calculate denominator: i²-1
        double denominator = pow(i, 2) - 1;

        // Apply alternating signs
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output result with precision
    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;

    // Read input
    scanf("%d", &n);

    // Generate and print each row of the triangle
    for (int i = 1; i <= n; ++i) {
        // Print leading spaces to center the digits
        for (int j = n - i; j > 0; --j) {
            printf(" ");
        }

        // Print the current row's digits
        for (int k = 0; k < i; ++k) {
            printf("%d", i);
        }

        // Move to the next line after each row
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

int main(void) {
    int numbers[NUM_NUMBERS];
    int guessed_positions[NUM_NUMBERS] = {0};
    int score = 0;
    char guess;

    // Generate 5 unique random numbers between 1 and 10
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }

    // Game loop
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("Numbers: ");
        for (int j = 0; j < NUM_NUMBERS; j++) {
            if (guessed_positions[j]) {
                printf("%d ", numbers[j]);
            } else {
                printf("* ");
            }
        }
        printf("\nPick position (1-%d): ", NUM_NUMBERS);
        scanf("%d", &guessed_positions[i]);

        // Validate input
        while (guessed_positions[i] < 1 || guessed_positions[i] > NUM_NUMBERS) {
            printf("Invalid position. Please enter a number between 1 and %d: ", NUM_NUMBERS);
            scanf("%d", &guessed_positions[i]);
        }

        printf("Guess even or odd (E/O): ");
        scanf(" %c", &guess);

        // Calculate correctness
        if ((numbers[guessed_positions[i] - 1] % 2 == 0 && guess == 'E') ||
            (numbers[guessed_positions[i] - 1] % 2 != 0 && guess == 'O')) {
            score += 5;
            printf("Correct! You win 5 points.\n");
        } else {
            printf("Incorrect. The number is %d.\n", numbers[guessed_positions[i] - 1]);
        }

        // Reveal the number
        guessed_positions[i] = 1;
    }

    // Display final score
    printf("\nFinal Score: %d\n", score);

    return 0;
}
